// wD_cat_49_52.js – Generate categoryInterpretations for Hexagrams 49-52
// Run: & "D:\AI_PROJECTS\Zero1Matrix\.nodejs\node-v22.14.0-win-x64\node.exe" "D:\AI_PROJECTS\Zero1Matrix\scripts\wD_cat_49_52.js"

const fs = require('fs');
const path = require('path');

// ====== CONFIG ======
const SRC = 'D:\\AI_PROJECTS\\Zero1Matrix\\src\\data\\categoryInterpretations.data.js';
const CAT_NAMES = {
  general:'一般', career:'工作事業', love:'感情關係', money:'金錢財務',
  people:'人際關係', family:'家庭親情', study:'學習考試', health:'健康身心',
  decision:'決策判斷', business:'創業經營', legal:'法律爭訟', spiritual:'靈性修行'
};

function E(hexId, cat, meaning, advice, warning, timing, basis, scoreAdj) {
  return {
    id: 'hex-' + String(hexId).padStart(3,'0') + '-' + cat,
    hexagramId: hexId,
    category: cat,
    categoryName: CAT_NAMES[cat],
    meaning, advice, warning, timing, basis,
    scoreAdjust: scoreAdj || {clarity:0,action:0,risk:0,change:0,support:5,timing:0},
    qualityLevel: 'refined',
    reviewed: false,
    needsHumanReview: true,
    version: '1.8.0-cat-hex49-52'
  };
}

// ====== VALIDATION ======
function validate(entries) {
  const cats = ['general','career','love','money','people','family','study','health','decision','business','legal','spiritual'];
  const errors = [];
  for (const hexId of [49,50,51,52]) {
    for (const cat of cats) {
      const e = entries.find(x => x.hexagramId === hexId && x.category === cat);
      if (!e) { errors.push('MISSING: hex-'+hexId+'-'+cat); continue; }
      if (e.meaning.length < 125) errors.push('hex-'+hexId+'-'+cat+' meaning too short: '+e.meaning.length);
      if (e.advice.length < 110) errors.push('hex-'+hexId+'-'+cat+' advice too short: '+e.advice.length);
      if (e.warning.length < 90) errors.push('hex-'+hexId+'-'+cat+' warning too short: '+e.warning.length);
      if (e.timing.length < 70) errors.push('hex-'+hexId+'-'+cat+' timing too short: '+e.timing.length);
      if (!Array.isArray(e.basis) || e.basis.length < 4) errors.push('hex-'+hexId+'-'+cat+' basis must be array of 4+: '+JSON.stringify(e.basis));
      if (e.qualityLevel !== 'refined') errors.push('hex-'+hexId+'-'+cat+' qualityLevel not refined');
    }
  }
  return errors;
}

// ====== WRITE OUTPUT ======
function writeOutput(newEntries) {
  const raw = fs.readFileSync(SRC, 'utf8');
  const prefix = raw.indexOf('window.Zero1MatrixData.categoryInterpretations = [');
  const prefixStr = raw.substring(0, prefix + 'window.Zero1MatrixData.categoryInterpretations = '.length);
  
  // Parse existing, remove any hex 49-52 entries
  const existing = JSON.parse(raw.replace('window.Zero1MatrixData = window.Zero1MatrixData || {};','').replace('window.Zero1MatrixData.categoryInterpretations = ','').replace(/;$/,''));
  const filtered = existing.filter(e => ![49,50,51,52].includes(e.hexagramId));
  
  const merged = [...filtered, ...newEntries];
  
  const out = 'window.Zero1MatrixData = window.Zero1MatrixData || {};\nwindow.Zero1MatrixData.categoryInterpretations = ' + JSON.stringify(merged) + ';';
  fs.writeFileSync(SRC, out, 'utf8');
  console.log('Written ' + merged.length + ' total entries to ' + SRC);
  console.log('New entries: ' + newEntries.length);
  return merged;
}

// ====== NODE CHECK ======
function nodeCheck() {
  try {
    const content = fs.readFileSync(SRC, 'utf8');
    // Extract JSON portion
    const jsonPart = content.replace('window.Zero1MatrixData = window.Zero1MatrixData || {};\nwindow.Zero1MatrixData.categoryInterpretations = ','').replace(/;$/,'');
    JSON.parse(jsonPart); // verify valid JSON
    console.log('JSON parse PASSED');
    return true;
  } catch(e) {
    console.error('JSON parse FAILED:', e.message);
    return false;
  }
}

// ==================== MAIN ====================
console.log('Starting generation of Hexagrams 49-52...');

const entries = [];

